SELECT COUNT(*) AS number_of_pokemon
FROM user_pokemon
WHERE user_id = 1;

SELECT COUNT(*) AS number_of_moves
FROM pokemon_moves
WHERE pokemon_id = 0;

SELECT pokemon_id, COUNT(move_id) AS number_of_moves
FROM pokemon_moves
GROUP BY pokemon_id;

SELECT effectiveness
FROM move_outcomes
WHERE damage_dealt > 40;

SELECT name, (attack + defense + special_attack + special_defense + speed + hp) AS total_stats
FROM pokemon
ORDER BY total_stats DESC;

SELECT user_id, COUNT(*) AS number_of_pokemon
FROM user_pokemon
GROUP BY user_id;
